    private void CreateAccountBtnActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_CreateAccountBtnActionPerformed
        // TODO add your handling code here:
        

    String fullname = txtFullname.getText().trim();
    String username = txtUsername.getText().trim();
    String sex = ((String) txtSex.getSelectedItem()).trim();
    String address = txtAddress.getText().trim();
    String age = txtAge.getText().trim();
    String nationality = (String) txtNationality.getSelectedItem();
    String pin = new String(txtPin.getPassword());
    String confirmPin = new String(jPasswordField1.getPassword());

    if (nationality == null || nationality.equals("Select Nationality")) {
        JOptionPane.showMessageDialog(this,
            "Please select your nationality.");
        txtNationality.requestFocus();
        return;
    }

    if (sex.equals("Select Sex")) {
        JOptionPane.showMessageDialog(this,
            "Please select your sex.");
        txtSex.requestFocus();
        return;
    }

    if (username.isEmpty() || !isGmailAddress(username)) {
        JOptionPane.showMessageDialog(this,
            "Please enter a valid Gmail address ending with @gmail.com");
        txtUsername.requestFocus();
        return;
    }

    // 🔐 PIN VALIDATION (6 digits only)
    if(!pin.matches("[0-9]{6}")){
        JOptionPane.showMessageDialog(this,
            "PIN must be exactly 6 digits (numbers only)");
        return;
    }

    // 🔐 CONFIRM PIN VALIDATION - Check if PIN and Confirm PIN match
    if(!pin.equals(confirmPin)){
        JOptionPane.showMessageDialog(this,
            "PIN and Confirm PIN do not match!\nPlease re-enter your PIN correctly.");
        txtPin.setText("");
        jPasswordField1.setText("");
        txtPin.requestFocus();
        return;
    }

    try {

        String hashedPin = SecurityUtil.hashPin(pin);

        ensureNationalityColumn();

        PreparedStatement pst = DB.connect().prepareStatement(
            "INSERT INTO users(fullname,username,sex,nationality,address,age,pin) VALUES(?,?,?,?,?,?,?)"
        );

        pst.setString(1, fullname);
        pst.setString(2, username);
        pst.setString(3, sex);
        pst.setString(4, nationality);
        pst.setString(5, address);
        pst.setInt(6, Integer.parseInt(age));
        pst.setString(7, hashedPin);

        pst.executeUpdate();

        JOptionPane.showMessageDialog(this,
            "Registration Successful!");
        SignInUsers loginFrame = new SignInUsers();
        loginFrame.setVisible(true);
        loginFrame.pack();
        loginFrame.setLocationRelativeTo(null);
        this.dispose();

        // clear fields
        txtFullname.setText("");
        txtUsername.setText("");
        txtSex.setSelectedIndex(0);
        txtAddress.setText("");
        txtAge.setText("");
        txtPin.setText("");
        txtNationality.setSelectedIndex(0);

    } catch(Exception e){
        System.out.println(e);
    }

    }//GEN-LAST:event_CreateAccountBtnActionPerformed

