    private void loadNationalityOptions() {
        txtNationality.removeAllItems();
        txtNationality.addItem("Select Nationality");
        txtNationality.addItem("Filipino");
        txtNationality.addItem("American");
        txtNationality.addItem("Chinese");
        txtNationality.addItem("British");
        txtNationality.addItem("French");
        txtNationality.addItem("German");
        txtNationality.addItem("Australian");
        txtNationality.addItem("Korean");
        txtNationality.addItem("Saudi / Saudi Arabian");
        txtNationality.addItem("Mexican");
        txtNationality.setSelectedIndex(0);
    }

    private boolean isGmailAddress(String email) {
        return email.matches("(?i)^[A-Z0-9._%+-]+@gmail\\.com$");
    }

    private void ensureNationalityColumn() {
        try (Connection connection = DB.connect()) {
            if (connection == null) {
                return;
            }

            ResultSet columns = connection.getMetaData().getColumns(null, null, "users", "nationality");
            boolean columnExists = columns.next();
            columns.close();

            if (!columnExists) {
                connection.createStatement().executeUpdate(
                    "ALTER TABLE users ADD COLUMN nationality VARCHAR(100) AFTER sex"
                );
            }
        } catch (Exception e) {
            System.out.println(e);
        }
    }

